<script>
(function(){
  "use strict";

  // ---------- shared 3D coin renderer (2D canvas, deterministic) ----------
  // We render a coin as a cylinder with reeded edge, front/back relief,
  // and a moving specular highlight. Everything is procedural.

  function metalShade(base, light, spec){
    // base: [r,g,b], light 0..1, spec 0..1 -> returns css rgb
    let r = base[0]*light + 255*spec;
    let g = base[1]*light + 255*spec;
    let b = base[2]*light + 255*spec;
    r=Math.max(0,Math.min(255,r));
    g=Math.max(0,Math.min(255,g));
    b=Math.max(0,Math.min(255,b));
    return "rgb("+(r|0)+","+(g|0)+","+(b|0)+")";
  }

  // Draw a coin into ctx at time t in [0,1]
  // opts: {cx,cy,size,base:[r,g,b], denom:string, emblem:bool, edgeRidge:int}
  function drawCoin(ctx, t, opts){
    const cx = opts.cx, cy = opts.cy, R = opts.size*0.5;
    const base = opts.base;
    // rotation about vertical axis (yaw) and flip about horizontal (pitch)
    const yaw = t*Math.PI*2;            // 0..2pi
    const pitch = Math.sin(t*Math.PI*2)*0.9; // flip both faces visible
    // light direction (fixed in view space) -> specular rakes as coin turns
    const Lx = -0.5, Ly = -0.7, Lz = 0.6;
    // normal of face depends on pitch/yaw
    const cosY=Math.cos(yaw), sinY=Math.sin(yaw);
    const cosP=Math.cos(pitch), sinP=Math.sin(pitch);
    // face normal (front face points +z in local)
    let nx = sinY*cosP;
    let ny = sinP;
    let nz = cosY*cosP;
    // dot with light
    let ndl = nx*Lx+ny*Ly+nz*Lz;
    let light = 0.45 + 0.55*Math.max(0,ndl);
    // specular: reflect or half-vector approx
    let spec = Math.pow(Math.max(0,ndl),18)*0.9;

    // thickness of coin in screen space (edge visible when yaw not aligned)
    const thick = R*0.16;
    const edgeVis = Math.abs(Math.sin(yaw)); // 0 when face-on, 1 when edge-on
    const edgeW = thick*edgeVis + 1;

    // ---- edge (reeded) ----
    if(edgeVis>0.02){
      const steps = opts.edgeRidge||48;
      for(let i=0;i<steps;i++){
        const a = (i/steps)*Math.PI*2;
        const ex = Math.cos(a), ey=Math.sin(a);
        // project edge point with yaw
        const px = cx + ex*R*cosY - ey*0*sinY;
        const py = cy + ey*R*cosP*0.96;
        // simple shading per ridge
        const ridge = (i%2===0)?0.7:0.45;
        ctx.fillStyle = metalShade(base, ridge*light, spec*0.2);
        ctx.fillRect(px-edgeW*0.5, py-edgeW*0.5, edgeW, edgeW*1.4);
      }
    }

    // ---- face ellipse (perspective squash by pitch) ----
    const squash = Math.abs(Math.cos(pitch));
    ctx.save();
    ctx.translate(cx,cy);
    ctx.scale(1, squash);
    // base disc
    const grad = ctx.createRadialGradient(-R*0.3,-R*0.3,R*0.1, 0,0,R);
    grad.addColorStop(0, metalShade(base, light*1.15, spec));
    grad.addColorStop(0.7, metalShade(base, light*0.9, spec*0.4));
    grad.addColorStop(1, metalShade(base, light*0.55, 0));
    ctx.beginPath();
    ctx.arc(0,0,R,0,Math.PI*2);
    ctx.fillStyle = grad;
    ctx.fill();
    // rim
    ctx.lineWidth = R*0.06;
    ctx.strokeStyle = metalShade(base, light*0.7, spec*0.3);
    ctx.stroke();

    // ---- relief: front emblem or back denomination ----
    const showFront = nz>0; // facing viewer
    ctx.rotate(yaw*0.0); // keep text upright-ish
    if(showFront){
      // emblem: raised ring + "W" + small tokens mark
      ctx.lineWidth=R*0.04;
      ctx.strokeStyle=metalShade(base, light*1.2, spec*0.6);
      ctx.beginPath();ctx.arc(0,0,R*0.72,0,Math.PI*2);ctx.stroke();
      ctx.fillStyle=metalShade(base, light*1.25, spec*0.7);
      ctx.font="bold "+(R*0.5)+"px ui-sans-serif,system-ui,sans-serif";
      ctx.textAlign="center";ctx.textBaseline="middle";
      ctx.fillText("W",0,-R*0.02);
      ctx.font="bold "+(R*0.12)+"px ui-sans-serif,system-ui,sans-serif";
      ctx.fillText("WASTED",0,R*0.42);
      ctx.fillText("MINT",0,R*0.56);
    } else {
      // back: denomination
      ctx.fillStyle=metalShade(base, light*1.2, spec*0.6);
      ctx.font="bold "+(R*0.22)+"px ui-sans-serif,system-ui,sans-serif";
      ctx.textAlign="center";ctx.textBaseline="middle";
      ctx.fillText(opts.denom,0,-R*0.06);
      ctx.font="bold "+(R*0.13)+"px ui-sans-serif,system-ui,sans-serif";
      ctx.fillText("TOKENS",0,R*0.22);
      // reeded inner circle
      ctx.lineWidth=R*0.03;
      ctx.strokeStyle=metalShade(base, light*0.9, spec*0.3);
      ctx.beginPath();ctx.arc(0,0,R*0.78,0,Math.PI*2);ctx.stroke();
    }
    ctx.restore();
  }

  // ---------- hero ----------
  const hero = document.getElementById("coin-hero");
  const hctx = hero.getContext("2d");
  function sizeHero(){
    const dpr = Math.min(2, window.devicePixelRatio||1);
    const rect = hero.getBoundingClientRect();
    hero.width = Math.max(2, rect.width*dpr);
    hero.height = Math.max(2, rect.height*dpr);
    hctx.setTransform(dpr,0,0,dpr,0,0);
  }
  sizeHero();
  window.addEventListener("resize", sizeHero);

  function renderHero(t){
    const w = hero.width/(window.devicePixelRatio||1);
    const h = hero.height/(window.devicePixelRatio||1);
    hctx.clearRect(0,0,w,h);
    // backdrop
    const bg = hctx.createLinearGradient(0,0,0,h);
    bg.addColorStop(0,"#0e1118");bg.addColorStop(1,"#0a0c11");
    hctx.fillStyle=bg;hctx.fillRect(0,0,w,h);
    const size = Math.min(w,h)*0.62;
    drawCoin(hctx, t, {
      cx:w/2, cy:h/2, size:size,
      base:[220,200,120], denom:"10,000", edgeRidge:64
    });
  }

  let raf=null, start=0, paused=false;
  function loop(ts){
    if(paused) return;
    if(!start) start=ts;
    const t = ((ts-start)%4000)/4000;
    renderHero(t);
    raf=requestAnimationFrame(loop);
  }
  renderHero(0);
  raf=requestAnimationFrame(loop);

  // ---------- edition canvases ----------
  const editions = [
    {sel:'bronze', base:[192,132,87], denom:"10,000"},
    {sel:'silver', base:[207,214,224], denom:"25,000"},
    {sel:'gold',   base:[233,196,106], denom:"50,000"},
    {sel:'black',  base:[60,64,74],    denom:"100,000"}
  ];
  editions.forEach(e=>{
    const tile = document.querySelector('.edition[data-edition="'+e.sel+'"]');
    const cv = tile.querySelector('.edition-canvas');
    const c = cv.getContext('2d');
    function size(){
      const r=cv.getBoundingClientRect();
      const dpr=Math.min(2,window.devicePixelRatio||1);
      cv.width=Math.max(2,r.width*dpr);
      cv.height=Math.max(2,r.height*dpr);
      c.setTransform(dpr,0,0,dpr,0,0);
      paint();
    }
    function paint(){
      const w=cv.width/(window.devicePixelRatio||1);
      const h=cv.height/(window.devicePixelRatio||1);
      c.clearRect(0,0,w,h);
      c.fillStyle="#0c0f15";c.fillRect(0,0,w,h);
      const size=Math.min(w,h)*0.74;
      // static 3/4 view
      drawCoin(c, 0.13, {cx:w/2,cy:h/2,size:size,base:e.base,denom:e.denom,edgeRidge:40});
    }
    size();
    window.addEventListener('resize',size);
  });

  // ---------- programmatic API ----------
  window.demo = {
    canvas: hero,
    setTime(t){
      paused = true;
      if(raf) cancelAnimationFrame(raf);
      t = Math.max(0, Math.min(1, t));
      renderHero(t);
    },
    pause(){
      paused = true;
      if(raf) cancelAnimationFrame(raf);
    }
  };
  // expose start for internal use if needed
  window.demo._resume = function(){
    if(paused){ paused=false; start=0; raf=requestAnimationFrame(loop); }
  };
})();
</script>
</body>
</html>
